import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. KURUMSAL PRESTİJ AYARLARI ---st.set_page_config(page_title="Focus AI | Master Mentorship", layout="wide")# --- 2. STRATEJİK VERİ (ÖSYM 2021-2025) ---MÜFREDAT = {    "TYT Matematik": {"Problemler": 12, "Sayılar": 3, "Geometri": 10},    "AYT Matematik": {"Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2},    "TYT Türkçe": {"Paragraf": 26, "Dil Bilgisi": 7},    "AYT Edebiyat": {"Divan": 5, "Cumhuriyet": 4, "Edebi Sanatlar": 2}}# --- 3. MERKEZİ HAFIZA ---if 'ogrenciler' not in st.session_state:    st.session_state.ogrenciler = pd.DataFrame(columns=["Ad Soyad", "Hedef", "Veli Tel"])if 'program' not in st.session_state:    st.session_state.program = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum"])# --- 4. SIDEBAR ---st.sidebar.title("🎯 Focus AI v5.1")st.sidebar.subheader("Bostanlı Çözüm VIP")role = st.sidebar.selectbox("Rol Seçiniz:", ["👨‍🏫 KOÇLUK MERKEZİ", "🎓 ÖĞRENCİ PANELİ"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Öğrenci Yok"]# ==========================================# 👨‍🏫 KOÇLUK MERKEZİ (BAŞARION'DAN DAHA GÜÇLÜ)# ==========================================if role == "👨‍🏫 KOÇLUK MERKEZİ":    st.title("🏛️ Master Coach Yönetim Paneli")        # Dashboard Metrikleri    c1, c2, c3 = st.columns(3)    c1.metric("Toplam Danışan", len(st.session_state.ogrenciler))    c2.metric("Sınav Odaklılık", "92%", "🚀 +4%")    c3.metric("Kritik Takip", "2 Öğrenci")    tabs = st.tabs(["📊 Performans Analizi", "📝 Stratejik Planlama", "👤 Kayıt Sistemi", "📲 Veli İletişimi"])    with tabs[0]: # Analiz        sel_o = st.selectbox("Analiz Edilecek Öğrenci", ogrenci_listesi)        col_r1, col_r2 = st.columns([2, 1])        with col_r1:            fig = go.Figure(data=go.Scatterpolar(r=[85, 75, 90, 60, 80], theta=['Akademik', 'Odak', 'Hız', 'Mental', 'Düzen'], fill='toself'))            fig.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 100])), title="Öğrenci Gelişim Radarı")            st.plotly_chart(fig, use_container_width=True)        with col_r2:            st.info("💡 **Koç Notu:** Öğrencinin deneme hızı artmış ancak mental dayanıklılığı düşüşte. Soru sayısını sabit tutup dinlenme sürelerini artıralım.")    with tabs[1]: # Planlama        with st.form("plan_form"):            o_odev = st.selectbox("Öğrenci", ogrenci_listesi)            d_odev = st.selectbox("Ders", list(MÜFREDAT.keys()))            k_odev = st.multiselect("Konu Seç (ÖSYM Soru Ağırlıklı)", list(MÜFREDAT[d_odev].keys()))            if st.form_submit_button("Planı Onayla"):                for k in k_odev:                    yeni = pd.DataFrame([[o_odev, d_odev, k, MÜFREDAT[d_odev][k], "Bekliyor"]], columns=st.session_state.program.columns)                    st.session_state.program = pd.concat([st.session_state.program, yeni], ignore_index=True)                st.success("Haftalık yol haritası oluşturuldu.")    with tabs[2]: # Kayıt        with st.form("kayit"):            n_ad = st.text_input("Öğrenci Ad Soyad")            n_hed = st.text_input("Hedef")            n_tel = st.text_input("Veli WhatsApp")            if st.form_submit_button("Sisteme Dahil Et"):                yeni_o = pd.DataFrame([[n_ad, n_hed, n_tel]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.rerun()        st.dataframe(st.session_state.ogrenciler, use_container_width=True)    with tabs[3]: # İletişim        st.subheader("📩 Veliye Dijital Karne Gönder")        if not st.session_state.ogrenciler.empty:            v_sel = st.selectbox("Raporlanacak Öğrenci", ogrenci_listesi)            v_tel = st.session_state.ogrenciler[st.session_state.ogrenciler["Ad Soyad"] == v_sel]["Veli Tel"].values[0]            msg = f"Sayın Velimiz, bugün {v_sel} ile yaptığımız analizde sınav hedeflerine %85 uyum saptanmıştır. Focus AI verilerine göre gelişim pozitiftir."            st.link_button("🟢 WhatsApp'tan Raporu İlet", f"https://wa.me/{v_tel}?text={msg.replace(' ', '%20')}")# ==========================================# 🎓 ÖĞRENCİ PANELİ# ==========================================else:    st.title("🎓 Öğrenci Gelişim Merkezi")    st.write("### ✅ Senin İçin Kritik Görevler")    if not st.session_state.program.empty:        for i, r in st.session_state.program.iterrows():            if r["Durum"] == "Bekliyor":                with st.expander(f"📌 {r['Ders']} | {r['Konu']} (Değeri: {r['Soru Yükü']} Soru)"):                    if st.button("Bitirdim!", key=i):                        st.session_state.program.at[i, "Durum"] = "Tamamlandı"                        st.rerun()    else:        st.success("Harika! Tüm hedeflerine ulaştın.")